mapper.select:
SELECT FROM elderly_info WHERE status = 1 AND (audit_status = 'APPROVED' OR audit_status IS NULL)
AND (name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR address LIKE CONCAT('%', #{keyword}, '%'))
AND care_level = #{careLevel}
AND living_alone = #{livingAlone}
ORDER BY care_level DESC, created_time DESC

